const alert = $input.first().json;
const srcip = alert.srcip;
if (!srcip || srcip === 'null') {
  return [{ json: { ...alert, enrichment: null } }];
}
const otxApiKey = $env.OTX_API_KEY || 'REPLACE';
try {
  const response = await fetch('https://otx.alienvault.com/api/v1/indicators/IPv4/' + srcip + '/general', {
    headers: { 'X-OTX-API-KEY': otxApiKey }
  });
  if (response.ok) {
    const data = await response.json();
    return [{ json: {
      ...alert,
      enrichment: {
        otx_score: data.reputation || 0,
        otx_pulses: data.pulse_count || 0,
        is_malicious: (data.pulse_count || 0) > 0
      }
    }}];
  }
} catch (e) { console.log('OTX failed: ' + e.message); }
return [{ json: { ...alert, enrichment: { status: 'skipped' } } }];

